public int minOperations(int[] nums, int[] target) {
    int n = nums.length;
    int sum_nums = 0;
    int sum_target = 0;
    for (int i = 0; i < n; i++) {
        sum_nums += nums[i];
        sum_target += target[i];
    }
    int diff = (sum_target - sum_nums) / 2;
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] > target[i]) {
            cnt += (nums[i] - target[i] - diff) / 2;
        }
    }
    return cnt;
}
```


